long long solve(std::vector<long long> nums, long long k) {
    unordered_map<long long, long long> prefixRemainder;
    prefixRemainder[0] = -1;
    long long sum = 0;
    vector<pair<long long, long long>> segments;

    for (long long i = 0; i < nums.size(); ++i) {
        sum += nums[i];
        long long rem = (sum % k + k) % k;
        if (prefixRemainder.count(rem)) {
            long long prev = prefixRemainder[rem];
            segments.emplace_back(prev + 1, i);
        }
        prefixRemainder[rem] = i;
    }

    if (segments.empty()) {
        long long total = 0;
        for (auto num : nums) total += num;
        return total;
    }

    sort(segments.begin(), segments.end(), [](const pair<long long, long long>& a, const pair<long long, long long>& b) {
        if (a.second == b.second) return a.first < b.first;
        return a.second < b.second;
